import{_ as a,o as i,c as e,a2 as r}from"./chunks/framework.DRBHoC6Q.js";const b=JSON.parse('{"title":"CEO现金流经营决策系统 V1.0 产品边界说明","description":"","frontmatter":{},"headers":[],"relativePath":"v1/product-boundary.md","filePath":"v1/product-boundary.md","lastUpdated":1783323851000}'),o={name:"v1/product-boundary.md"};function h(t,l,u,d,n,c){return i(),e("div",null,[...l[0]||(l[0]=[r('<h1 id="ceo现金流经营决策系统-v1-0-产品边界说明" tabindex="-1">CEO现金流经营决策系统 V1.0 产品边界说明 <a class="header-anchor" href="#ceo现金流经营决策系统-v1-0-产品边界说明" aria-label="Permalink to &quot;CEO现金流经营决策系统 V1.0 产品边界说明&quot;">​</a></h1><p>文档版本：V1.0<br> 项目名称：CEO现金流经营决策系统 V1.0<br> 项目简称：CEO现金流驾驶舱 / 现金流指挥中枢<br> 当前阶段：已有可交互前端 Demo，准备进入 V1.0 产品化落地阶段</p><h2 id="一、项目名称" tabindex="-1">一、项目名称 <a class="header-anchor" href="#一、项目名称" aria-label="Permalink to &quot;一、项目名称&quot;">​</a></h2><p>CEO现金流经营决策系统 V1.0</p><p>也可简称：</p><ul><li>CEO现金流驾驶舱</li><li>现金流指挥中枢</li></ul><h2 id="二、业务背景" tabindex="-1">二、业务背景 <a class="header-anchor" href="#二、业务背景" aria-label="Permalink to &quot;二、业务背景&quot;">​</a></h2><p>老板希望通过 AI 和数据系统，解决经营管理中“钱从哪里来、钱花到哪里去、未来现金流是否有风险”的问题。</p><p>当前企业的收入、支出、回款、审批、预算等数据分散在财务 Excel、业务表、银行流水、审批系统或人工记录中，老板在做经营判断时缺少统一依据。</p><p>因此需要先建设一个面向 CEO 和 CFO 的现金流经营驾驶舱，把收入、支出、回款风险、现金流缺口、管理费用阈值等关键数据统一展示，并在异常时自动预警、自动派发任务，形成经营动作闭环。</p><h2 id="三、目标用户" tabindex="-1">三、目标用户 <a class="header-anchor" href="#三、目标用户" aria-label="Permalink to &quot;三、目标用户&quot;">​</a></h2><h3 id="_3-1-ceo-老板" tabindex="-1">3.1 CEO / 老板 <a class="header-anchor" href="#_3-1-ceo-老板" aria-label="Permalink to &quot;3.1 CEO / 老板&quot;">​</a></h3><ul><li>每天看现金流是否安全；</li><li>判断收入、支出、回款是否异常；</li><li>决定哪些事项需要自己介入；</li><li>看系统是否已经自动派人处理。</li></ul><h3 id="_3-2-cfo-财务负责人" tabindex="-1">3.2 CFO / 财务负责人 <a class="header-anchor" href="#_3-2-cfo-财务负责人" aria-label="Permalink to &quot;3.2 CFO / 财务负责人&quot;">​</a></h3><ul><li>定义字段口径；</li><li>确认算法规则；</li><li>复核数据来源；</li><li>管理预算、支出、现金流预测。</li></ul><h3 id="_3-3-业务负责人-商务-销售" tabindex="-1">3.3 业务负责人 / 商务 / 销售 <a class="header-anchor" href="#_3-3-业务负责人-商务-销售" aria-label="Permalink to &quot;3.3 业务负责人 / 商务 / 销售&quot;">​</a></h3><ul><li>接收回款、催收、业务异常任务；</li><li>反馈跟进结果；</li><li>对收入风险负责。</li></ul><h3 id="_3-4-财务-行政-审批相关人员" tabindex="-1">3.4 财务 / 行政 / 审批相关人员 <a class="header-anchor" href="#_3-4-财务-行政-审批相关人员" aria-label="Permalink to &quot;3.4 财务 / 行政 / 审批相关人员&quot;">​</a></h3><ul><li>处理支出复核；</li><li>补充单据；</li><li>协助完成费用归类和审批判断。</li></ul><h2 id="四、核心场景" tabindex="-1">四、核心场景 <a class="header-anchor" href="#四、核心场景" aria-label="Permalink to &quot;四、核心场景&quot;">​</a></h2><ol><li>CEO 每天打开驾驶舱，看本月现金流是否有缺口；</li><li>CEO 查看本月收入、支出、预计回款和实际回款情况；</li><li>系统发现某笔应收款超过历史到账时间，自动预警；</li><li>系统将回款异常任务派发给对应商务或业务负责人；</li><li>某条业务线实收率预计不达标，系统提前预警；</li><li>支出审批前，系统判断这笔钱是否会影响现金流或超预算；</li><li>CFO 查看每个数字的数据来源、计算规则和复核状态；</li><li>老板通过 AI 助手直接提问：“这个月现金够不够？”“今天该追谁的款？”“管理费用还能花多少？”</li></ol><h2 id="五、当前-demo-页面" tabindex="-1">五、当前 Demo 页面 <a class="header-anchor" href="#五、当前-demo-页面" aria-label="Permalink to &quot;五、当前 Demo 页面&quot;">​</a></h2><p>当前 Demo 已包含以下页面：</p><h3 id="_5-1-ai-助手" tabindex="-1">5.1 AI 助手 <a class="header-anchor" href="#_5-1-ai-助手" aria-label="Permalink to &quot;5.1 AI 助手&quot;">​</a></h3><ul><li>支持用自然语言提问现金流、回款、审批、管理费用等问题；</li><li>当前 AI 主要负责表达和解释，底层数字由规则引擎计算。</li></ul><h3 id="_5-2-今日清单" tabindex="-1">5.2 今日清单 <a class="header-anchor" href="#_5-2-今日清单" aria-label="Permalink to &quot;5.2 今日清单&quot;">​</a></h3><ul><li>聚合今天需要处理的现金流、回款、支出、风险任务；</li><li>展示责任人、风险等级、建议动作。</li></ul><h3 id="_5-3-驾驶舱" tabindex="-1">5.3 驾驶舱 <a class="header-anchor" href="#_5-3-驾驶舱" aria-label="Permalink to &quot;5.3 驾驶舱&quot;">​</a></h3><ul><li>展示本月现金流缺口、预计回款、计划支出、管理费用阈值等核心指标。</li></ul><h3 id="_5-4-流水复核" tabindex="-1">5.4 流水复核 <a class="header-anchor" href="#_5-4-流水复核" aria-label="Permalink to &quot;5.4 流水复核&quot;">​</a></h3><ul><li>对收入、支出、信息流进行分类；</li><li>支持人工复核和改标。</li></ul><h3 id="_5-5-风险派发" tabindex="-1">5.5 风险派发 <a class="header-anchor" href="#_5-5-风险派发" aria-label="Permalink to &quot;5.5 风险派发&quot;">​</a></h3><ul><li>展示高风险、关注、正常事项；</li><li>可看到责任人和建议动作。</li></ul><h3 id="_5-6-支出审批" tabindex="-1">5.6 支出审批 <a class="header-anchor" href="#_5-6-支出审批" aria-label="Permalink to &quot;5.6 支出审批&quot;">​</a></h3><ul><li>输入拟付款金额、科目、用途、单据状态后，系统给出审批建议。</li></ul><h3 id="_5-7-回款风险" tabindex="-1">5.7 回款风险 <a class="header-anchor" href="#_5-7-回款风险" aria-label="Permalink to &quot;5.7 回款风险&quot;">​</a></h3><ul><li>展示应收款、逾期天数、负责人、风险等级、跟进状态。</li></ul><h3 id="_5-8-参数配置" tabindex="-1">5.8 参数配置 <a class="header-anchor" href="#_5-8-参数配置" aria-label="Permalink to &quot;5.8 参数配置&quot;">​</a></h3><ul><li>配置年营收、管理费用比例、账期、预算、阈值等参数；</li><li>标注哪些数据仍待财务复核。</li></ul><h2 id="六、v1-0-必做" tabindex="-1">六、V1.0 必做 <a class="header-anchor" href="#六、v1-0-必做" aria-label="Permalink to &quot;六、V1.0 必做&quot;">​</a></h2><h3 id="_6-1-字段定义清楚" tabindex="-1">6.1 字段定义清楚 <a class="header-anchor" href="#_6-1-字段定义清楚" aria-label="Permalink to &quot;6.1 字段定义清楚&quot;">​</a></h3><ul><li>每个指标叫什么；</li><li>给 CEO 看的名称是什么；</li><li>CFO 认可的财务定义是什么。</li></ul><h3 id="_6-2-算法规则清楚" tabindex="-1">6.2 算法规则清楚 <a class="header-anchor" href="#_6-2-算法规则清楚" aria-label="Permalink to &quot;6.2 算法规则清楚&quot;">​</a></h3><ul><li>每个数字怎么计算；</li><li>公式是什么；</li><li>哪些参数参与计算。</li></ul><h3 id="_6-3-数据来源清楚" tabindex="-1">6.3 数据来源清楚 <a class="header-anchor" href="#_6-3-数据来源清楚" aria-label="Permalink to &quot;6.3 数据来源清楚&quot;">​</a></h3><ul><li>数据来自银行流水、财务 Excel、业务系统、审批系统还是人工导入；</li><li>每个数据由谁维护；</li><li>谁负责复核。</li></ul><h3 id="_6-4-现金流缺口判断" tabindex="-1">6.4 现金流缺口判断 <a class="header-anchor" href="#_6-4-现金流缺口判断" aria-label="Permalink to &quot;6.4 现金流缺口判断&quot;">​</a></h3><ul><li>能判断本月是否缺钱；</li><li>能看到预计收入、预计支出、可用现金和缺口。</li></ul><h3 id="_6-5-回款预测与预警" tabindex="-1">6.5 回款预测与预警 <a class="header-anchor" href="#_6-5-回款预测与预警" aria-label="Permalink to &quot;6.5 回款预测与预警&quot;">​</a></h3><ul><li>根据历史到账时间判断某笔款是否异常；</li><li>例如约定每月 15 号到账，超过时间未到账要预警。</li></ul><h3 id="_6-6-任务自动派发" tabindex="-1">6.6 任务自动派发 <a class="header-anchor" href="#_6-6-任务自动派发" aria-label="Permalink to &quot;6.6 任务自动派发&quot;">​</a></h3><ul><li>回款异常后，系统自动生成任务；</li><li>派发给对应商务、销售或业务负责人。</li></ul><h3 id="_6-7-预警-sop" tabindex="-1">6.7 预警 SOP <a class="header-anchor" href="#_6-7-预警-sop" aria-label="Permalink to &quot;6.7 预警 SOP&quot;">​</a></h3><ul><li>明确先提醒谁；</li><li>多久未处理升级给谁；</li><li>什么情况下 CEO 可见。</li></ul><h3 id="_6-8-支出审批判断" tabindex="-1">6.8 支出审批判断 <a class="header-anchor" href="#_6-8-支出审批判断" aria-label="Permalink to &quot;6.8 支出审批判断&quot;">​</a></h3><ul><li>判断支出是否超预算；</li><li>是否影响现金流；</li><li>是否缺少合同、结算单等必要依据。</li></ul><h3 id="_6-9-ai-助手问答" tabindex="-1">6.9 AI 助手问答 <a class="header-anchor" href="#_6-9-ai-助手问答" aria-label="Permalink to &quot;6.9 AI 助手问答&quot;">​</a></h3><ul><li>支持老板用自然语言问核心经营问题；</li><li>回答必须带依据，不能凭空生成结论。</li></ul><h2 id="七、v1-0-暂不做" tabindex="-1">七、V1.0 暂不做 <a class="header-anchor" href="#七、v1-0-暂不做" aria-label="Permalink to &quot;七、V1.0 暂不做&quot;">​</a></h2><ol><li>暂不直接替代钉钉审批流；</li><li>暂不做真实付款、打款、转账等资金动作；</li><li>暂不做复杂 ERP / 财务系统全量替代；</li><li>暂不做所有岗位的 AI 员工配置；</li><li>暂不做完整人事、考勤、绩效管理；</li><li>暂不做全公司所有业务指标，只先围绕现金流、收入、支出、回款；</li><li>暂不让 AI 自己决定财务口径；</li><li>暂不把未经 CFO 复核的数据作为正式经营结论。</li></ol><h2 id="八、ai-能力" tabindex="-1">八、AI 能力 <a class="header-anchor" href="#八、ai-能力" aria-label="Permalink to &quot;八、AI 能力&quot;">​</a></h2><p>V1.0 中 AI 的定位不是“替代财务做账”，而是“经营副驾”。</p><h3 id="_8-1-主要能力" tabindex="-1">8.1 主要能力 <a class="header-anchor" href="#_8-1-主要能力" aria-label="Permalink to &quot;8.1 主要能力&quot;">​</a></h3><h4 id="自然语言问答" tabindex="-1">自然语言问答 <a class="header-anchor" href="#自然语言问答" aria-label="Permalink to &quot;自然语言问答&quot;">​</a></h4><ul><li>老板可以直接问：“这个月现金够不够？”“今天该追谁回款？”</li></ul><h4 id="数据解释" tabindex="-1">数据解释 <a class="header-anchor" href="#数据解释" aria-label="Permalink to &quot;数据解释&quot;">​</a></h4><ul><li>解释某个数字是怎么来的；</li><li>说明计算依据和数据来源。</li></ul><h4 id="风险识别" tabindex="-1">风险识别 <a class="header-anchor" href="#风险识别" aria-label="Permalink to &quot;风险识别&quot;">​</a></h4><ul><li>发现回款逾期；</li><li>发现实收率不达标；</li><li>发现支出超预算；</li><li>发现现金流缺口。</li></ul><h4 id="任务建议与派发" tabindex="-1">任务建议与派发 <a class="header-anchor" href="#任务建议与派发" aria-label="Permalink to &quot;任务建议与派发&quot;">​</a></h4><ul><li>根据规则生成任务；</li><li>建议责任人和处理动作。</li></ul><h4 id="预警总结" tabindex="-1">预警总结 <a class="header-anchor" href="#预警总结" aria-label="Permalink to &quot;预警总结&quot;">​</a></h4><ul><li>每天生成老板可读的经营摘要；</li><li>告诉老板哪些正常、哪些异常、哪些需要介入。</li></ul><h3 id="_8-2-ai-不负责" tabindex="-1">8.2 AI 不负责 <a class="header-anchor" href="#_8-2-ai-不负责" aria-label="Permalink to &quot;8.2 AI 不负责&quot;">​</a></h3><ul><li>编造财务数据；</li><li>自行修改财务口径；</li><li>直接发起付款；</li><li>绕过 CFO 复核；</li><li>替代正式审批责任人。</li></ul><h2 id="九、知识来源" tabindex="-1">九、知识来源 <a class="header-anchor" href="#九、知识来源" aria-label="Permalink to &quot;九、知识来源&quot;">​</a></h2><p>系统知识来源包括：</p><ol><li>老板口述需求；</li><li>CFO 确认的财务口径；</li><li>财务 Excel 表；</li><li>银行流水；</li><li>应收 / 应付数据；</li><li>支出审批数据；</li><li>业务线收入数据；</li><li>历史回款时间；</li><li>管理费用预算规则；</li><li>公司内部 SOP 和审批规则。</li></ol><p>所有核心字段、算法、阈值必须由老板和 CFO 共同确认。</p><h2 id="十、老板最关心的结果" tabindex="-1">十、老板最关心的结果 <a class="header-anchor" href="#十、老板最关心的结果" aria-label="Permalink to &quot;十、老板最关心的结果&quot;">​</a></h2><p>老板最关心的不是页面有多少功能，而是每天能不能回答这几个问题：</p><ol><li>今天公司现金流安全吗？</li><li>本月会不会缺钱？</li><li>哪些钱该进还没进？</li><li>哪些支出现在不能随便批？</li><li>哪条业务线收入有风险？</li><li>谁今天必须去处理？</li><li>AI 有没有在我看到之前先自动派发任务？</li><li>哪些事情最后才需要我亲自介入？</li></ol><p>一句话总结：</p><blockquote><p>V1.0 的目标是让老板每天知道：钱够不够、风险在哪、谁在处理、要不要我介入。</p></blockquote>',84)])])}const q=a(o,[["render",h]]);export{b as __pageData,q as default};
